package main

import (
	"fmt"
	"strings"
)

type Processor struct {
	Name  string
	Count int
}

func (p *Processor) Process(items []string) []string {
	results := make([]string, 0, len(items))
	for _, item := range items {
		if item == "" {
			continue
		}
		clean := strings.ToLower(strings.TrimSpace(item))
		results = append(results, clean)
		p.Count++
	}
	return results
}

func main() {
	p := &Processor{Name: "main"}
	fmt.Println(p.Process([]string{"a", "b"}))
}

